command:
// =========================
// VILLAGE GENERATOR
// Sandbox Generator
// Requires: Settlement Name Generator macro
// =========================

function roll(sides) {
    return Math.ceil(Math.random() * sides);
}

function tableRoll(rollValue, table) {
    return table.find(row => rollValue >= row.min && rollValue <= row.max);
}

function uniqueRolls(count, sides) {
    const results = [];
    while (results.length < count) {
        const r = roll(sides);
        if (!results.includes(r)) results.push(r);
    }
    return results;
}

// -------------------------
// SETTLEMENT NAME
// -------------------------

let settlementName = "Unknown Village";
let settlementNameFormat = "";
let settlementNameRolls = [];

const nameMacro = game.macros.getName("Settlement Name Generator");

if (nameMacro) {
    await nameMacro.execute();

    settlementName = globalThis.generatedSettlementName ?? "Unknown Village";
    settlementNameFormat = globalThis.generatedSettlementNameFormat ?? "";
    settlementNameRolls = globalThis.generatedSettlementNameRolls ?? [];
}

// -------------------------
// TABLES
// -------------------------

const villageSizeTable = [
    { min: 1, max: 2, size: "Small", grade: 1 },
{ min: 3, max: 5, size: "Medium", grade: 2 },
{ min: 6, max: 6, size: "Big", grade: 3 }
];

const occupations = [
    "Brewing / Viticulture",
"Fishing",
"Hunting",
"Logging",
"Mining",
"Pottery"
];

const occupationDescriptions = {
    "Brewing / Viticulture": "The village has breweries, vineyards, or local alcohol production.",
    "Fishing": "The village relies on nearby rivers, lakes, coastlines, or fisheries.",
    "Hunting": "The village produces hides, meat, furs, or leatherwork through hunting.",
    "Logging": "The village works nearby woods and likely has sawmills or timber yards.",
    "Mining": "The village exists near mines, quarries, or useful mineral deposits.",
    "Pottery": "The village has workshops, kilns, clay pits, or local pottery trade."
};

const layouts = [
    "Heap",
"Round",
"Row"
];

const layoutDescriptions = {
    "Heap": "Buildings are clustered irregularly, giving the village an organic, messy layout.",
    "Round": "Buildings form a rough circle around a center, green, well, shrine, or defensive point.",
    "Row": "Buildings are lined along a road, river, ridge, or other travel route."
};

const pointsOfInterest = [
    "Abandoned building",
"Apothecary",
"Bakery",
"Burnt/Ruined building",
"Butcher",
"Castle-farm",
"Church",
"Famous person’s house",
"General store",
"Graveyard",
"Guard post",
"Guildhouse",
"Gypsy wagon",
"Horse stables",
"Library",
"Mill",
"Monument/Memorial",
"Orchard",
"School",
"Tailor"
];

const defensesTable = [
    { min: 1, max: 3, result: "Wooden palisade" },
{ min: 4, max: 5, result: "Motte / mound" },
{ min: 6, max: 6, result: "Chevaux de frise" },
{ min: 7, max: 7, result: "Moat / trench" },
{ min: 8, max: 8, result: "Watchtowers" }
];

const dispositions = [
    { min: 2, max: 2, result: "Attack on sight" },
{ min: 3, max: 5, result: "Hostile" },
{ min: 6, max: 8, result: "Neutral" },
{ min: 9, max: 11, result: "Welcoming" },
{ min: 12, max: 12, result: "Enthusiastic" }
];

const dispositionDescriptions = {
    "Attack on sight": "The villagers immediately treat outsiders as enemies.",
    "Hostile": "The villagers are suspicious, unfriendly, or openly threatening.",
    "Neutral": "The villagers are cautious but not aggressive.",
    "Welcoming": "The villagers are friendly and willing to talk, trade, or help.",
    "Enthusiastic": "The villagers are very happy to see travelers and may actively offer aid."
};

const neutralRulerDisposition = [
    "Hostile",
"Hostile",
"Hostile",
"Welcoming",
"Welcoming",
"Welcoming"
];

const notableNPCs = [
    "Aggressive guard",
"Annoying minstrel",
"Bandit in disguise",
"Beggar who knows a lot",
"Curious waitress",
"Cute dog",
"Frightened peasant",
"Lonely widow",
"Misunderstood witch",
"Old fool/hag",
"One-handed lumberjack",
"Retired mercenary",
"Seasoned adventurer",
"Sick child",
"Stubborn magician",
"Talented craftsman",
"Traveling merchant",
"Troubled hunter",
"Vampire/Werewolf hunter",
"Village idiot"
];

const rulers = [
    "Bandits",
"Council",
"Mayor",
"Merchant",
"Priest",
"Vampire/Lycanthrope",
"Village elder",
"Witch"
];

const secrets = [
    "Animals turned human",
"Curse",
"Elder god cult",
"Eternal youth",
"Hidden treasure",
"Hiding outlaws",
"Hivemind",
"Inability to leave",
"Pact with a demon",
"Sadistic rituals",
"Secret society",
"Underground galleries"
];

const eventTiming = [
    { min: 1, max: 1, result: "Ended earlier" },
{ min: 2, max: 4, result: "Is happening now" },
{ min: 5, max: 6, result: "Will take place in the future" }
];

const villageEvents = [
    "Adventurers passing by",
"Announcement by a crier",
"Ceremony / wedding, etc.",
"Controlled by monsters",
"Disappearances",
"Famine",
"Festival/Fair",
"Fire",
"Looting",
"Market day",
"Plague",
"Visit of a notable / lord, etc."
];

// -------------------------
// ROLLS
// -------------------------

let sizeRoll = roll(6);
let sizeData = tableRoll(sizeRoll, villageSizeTable);
let villageSize = sizeData.size;
let grade = sizeData.grade;
let population = grade * 50;

let occupationCheckRoll = roll(6);
let hasExtraOccupation = occupationCheckRoll === 1;
let occupationRoll = null;
let occupation = "Farming and cattle breeding only";
let occupationDescription = "Every village already has farming, crop fields, meadows, and cattle breeding.";

if (hasExtraOccupation) {
    occupationRoll = roll(6);
    occupation = occupations[occupationRoll - 1];
    occupationDescription = occupationDescriptions[occupation];
}

let layoutRoll = roll(3);
let layout = layouts[layoutRoll - 1];

let poiRolls = uniqueRolls(grade, 20);
let poiResults = poiRolls.map(r => ({
    roll: r,
    result: pointsOfInterest[r - 1]
}));

let defenseRolls = uniqueRolls(grade, 8);
let defenseResults = defenseRolls.map(r => ({
    roll: r,
    result: tableRoll(r, defensesTable).result
}));

let guardBaseRoll = roll(3);
let guards = (guardBaseRoll + 3) * grade;

let dispositionDie1 = roll(6);
let dispositionDie2 = roll(6);
let dispositionTotal = dispositionDie1 + dispositionDie2;
let villageDisposition = tableRoll(dispositionTotal, dispositions).result;

let rulerRoll = roll(8);
let ruler = rulers[rulerRoll - 1];

let rulerDispositionRoll = roll(6);
let rulerDisposition;

if (villageDisposition === "Neutral") {
    rulerDisposition = neutralRulerDisposition[rulerDispositionRoll - 1];
} else {
    rulerDisposition = rulerDispositionRoll <= 4
    ? `Same as villagers (${villageDisposition})`
    : `Opposite of villagers`;
}

let npcRolls = uniqueRolls(grade, 20);
let npcResults = npcRolls.map(r => ({
    roll: r,
    result: notableNPCs[r - 1]
}));

let secretCheckRoll = roll(6);
let hasSecret = secretCheckRoll === 1;
let secretRoll = null;
let secret = "None";

if (hasSecret) {
    secretRoll = roll(12);
    secret = secrets[secretRoll - 1];
}

let eventCheckRoll = roll(6);
let hasEvent = eventCheckRoll === 1;
let eventTimingRoll = null;
let eventTime = "None";
let eventRoll = null;
let villageEvent = "None";

if (hasEvent) {
    eventTimingRoll = roll(6);
    eventTime = tableRoll(eventTimingRoll, eventTiming).result;

    eventRoll = roll(12);
    villageEvent = villageEvents[eventRoll - 1];
}

// -------------------------
// OUTPUT
// -------------------------

let output = `
<h2>Village Generator</h2>

<h3>Settlement Name</h3>
<p><b>Name:</b> ${settlementName}</p>
<p><b>Format:</b> ${settlementNameFormat}</p>
<ul>
${settlementNameRolls.map(r => `<li>${r}</li>`).join("")}
</ul>

<hr>

<h3>Size</h3>
<p><b>Size Roll:</b> d6 = ${sizeRoll}</p>
<p><b>Village Size:</b> ${villageSize}</p>
<p><b>Grade:</b> ${grade}</p>
<p><b>Approx. Population:</b> ${population}</p>

<hr>

<h3>Occupations</h3>
<p><b>Base Occupations:</b> Farming and cattle breeding</p>
<p><b>Extra Occupation Check:</b> d6 = ${occupationCheckRoll}</p>
<p><b>Has Extra Occupation:</b> ${hasExtraOccupation ? "Yes" : "No"}</p>
${hasExtraOccupation ? `<p><b>Occupation Roll:</b> d6 = ${occupationRoll}</p>` : ""}
<p><b>Occupation:</b> ${occupation}</p>
<p><i>${occupationDescription}</i></p>

<hr>

<h3>Layout</h3>
<p><b>Layout Roll:</b> d3 = ${layoutRoll}</p>
<p><b>Layout:</b> ${layout}</p>
<p><i>${layoutDescriptions[layout]}</i></p>

<hr>

<h3>Points of Interest</h3>
<p>Every village has at least a <b>blacksmith</b>, <b>market</b>, <b>tavern</b>, and <b>well</b>.</p>
<p><b>Special POI Rolls:</b> Roll d20 once per grade.</p>
<ul>
${poiResults.map(p => `<li>d20 = ${p.roll} → ${p.result}</li>`).join("")}
</ul>

<hr>

<h3>Defense</h3>
<p><b>Defense Rolls:</b> Roll d8 once per grade, rerolling duplicates.</p>
<ul>
${defenseResults.map(d => `<li>d8 = ${d.roll} → ${d.result}</li>`).join("")}
</ul>
<p><b>Guard Roll:</b> (d3 + 3) × grade = (${guardBaseRoll} + 3) × ${grade}</p>
<p><b>Guards:</b> ${guards}</p>

<hr>

<h3>Disposition</h3>
<p><b>Villager Disposition Roll:</b> 2d6 = ${dispositionDie1} + ${dispositionDie2} = ${dispositionTotal}</p>
<p><b>Villager Disposition:</b> ${villageDisposition}</p>
<p><i>${dispositionDescriptions[villageDisposition]}</i></p>

<p><b>Ruler Roll:</b> d8 = ${rulerRoll}</p>
<p><b>Ruler:</b> ${ruler}</p>

<p><b>Ruler Disposition Roll:</b> d6 = ${rulerDispositionRoll}</p>
<p><b>Ruler Disposition:</b> ${rulerDisposition}</p>

<hr>

<h3>Notable NPCs</h3>
<p><b>NPC Rolls:</b> Roll d20 once per grade.</p>
<ul>
${npcResults.map(n => `<li>d20 = ${n.roll} → ${n.result}</li>`).join("")}
</ul>

<hr>

<h3>Secret</h3>
<p><b>Secret Check:</b> d6 = ${secretCheckRoll}</p>
<p><b>Has Secret:</b> ${hasSecret ? "Yes" : "No"}</p>
${hasSecret ? `<p><b>Secret Roll:</b> d12 = ${secretRoll}</p>` : ""}
<p><b>Secret:</b> ${secret}</p>

<hr>

<h3>Event</h3>
<p><b>Event Check:</b> d6 = ${eventCheckRoll}</p>
<p><b>Has Event:</b> ${hasEvent ? "Yes" : "No"}</p>
${hasEvent ? `
    <p><b>Event Timing Roll:</b> d6 = ${eventTimingRoll}</p>
    <p><b>Timing:</b> ${eventTime}</p>
    <p><b>Event Roll:</b> d12 = ${eventRoll}</p>
    <p><b>Event:</b> ${villageEvent}</p>
    ` : `<p><b>Event:</b> None</p>`}

    <hr>

    <h3>Quick Summary</h3>
    <p>
    <b>${settlementName}</b> is a <b>${villageSize.toLowerCase()}</b> village of about
    <b>${population}</b> people. It is laid out in a <b>${layout.toLowerCase()}</b> pattern.
    The village mainly supports <b>farming and cattle breeding</b>${hasExtraOccupation ? `, with extra work in <b>${occupation.toLowerCase()}</b>` : ""}.
    The villagers are <b>${villageDisposition.toLowerCase()}</b>.
    The village is ruled by <b>${ruler.toLowerCase()}</b>.
    ${hasSecret ? ` Secretly, the village hides: <b>${secret.toLowerCase()}</b>.` : ""}
    ${hasEvent ? ` Event: <b>${villageEvent}</b> — ${eventTime.toLowerCase()}.` : ""}
    </p>
    `;

    ChatMessage.create({
        speaker: ChatMessage.getSpeaker(),
                       content: output
    });
